<?php  namespace App\Http\Controllers\Public;  use App\Http\Controllers\Controller; use App\Http\Requests\CareerApplicationFormRequest; use App\Models\Job; use App\Models\JobApplication;  class CareerController extends Controller {     public function index()     {         $jobs = Job::query()             ->where("is_active", true)             ->where("is_published", true)             ->orderBy("id", "desc")             ->paginate(config("hopn.pagination.default", 15));          return view("public.careers.index", compact("jobs"));     }      public function show(string $lang, string $slug)     {         $job = Job::query()             ->where("slug", $slug)             ->where("is_active", true)             ->firstOrFail();          return view("public.careers.show", compact("job"));     }      public function apply(CareerApplicationFormRequest $request, string $lang, string $slug)     {         $job = Job::query()->where("slug", $slug)->firstOrFail();         $data = $request->validated();          $cvPath = $request->file("cv")->store("career-cv", "public");          JobApplication::create([             "job_id"       => $job->id,             "full_name"    => $data["name"],             "email"        => $data["email"],             "phone"        => $data["phone"] ?? null,             "cover_letter" => $data["cover_letter"] ?? null,             "cv_path"      => $cvPath,             "status"       => "new",         ]);          return back()->with("status", "Your application has been submitted! We will review it and get back to you.");     } }